import { Dimensions, Platform, type ViewStyle } from 'react-native';
import { breakpoints, type IStyleClasses, mapCssProperties, isThemeToken } from '@lmb/kitsconcerto-types';
import { CSS_VAR_MAP } from './cssVarMap';

// Dynamic color map — defaults to static CSS_VAR_MAP, overridden by KitsThemeProvider
let _activeColorMap: Record<string, string> = CSS_VAR_MAP;

/** Sets the active color map (called by KitsThemeProvider on native) */
export function setActiveColorMap(map: Record<string, string>) {
  _activeColorMap = map;
}

/** Returns the active color map */
export function getActiveColorMap(): Record<string, string> {
  return _activeColorMap;
}

export type StyleContext = {
  platform: 'ios' | 'android';
  width: number;
  height: number;
  orientation: 'portrait' | 'landscape';
  device: 'phone' | 'tablet';
  breakpoint: keyof typeof breakpoints;
};

/**
 * Strips the `var()` wrapper from a CSS variable string.
 * e.g. `var(--primary-500)` → `--primary-500`
 */
export const normalizeColor = (color: string): string => {
  const match = color.match(/^var\((--[^)]+)\)$/);
  return match ? match[1]! : color;
};

/**
 * Resolves a CSS variable `var(--xyz)` to its native hex value via the active color map.
 * Non-variable strings are returned unchanged.
 */
export function resolveCssVar(value: string): string {
  const varMatch = value.match(/^var\(\s*(--[^)]+)\s*\)$/);
  if (!varMatch) return value;
  const varName = varMatch[1]!;
  return _activeColorMap[varName] ?? CSS_VAR_MAP[varName] ?? value;
}

/**
 * Resolves theme tokens (dot-notation, semantic, $-prefixed) to native values.
 * - 'blue.500' → lookup --kits-blue-500 in color map
 * - 'primary' → lookup --kits-primary in color map
 * - '$spacing.4' → '1rem' (then further converted by toNativeValue)
 */
export function resolveThemeTokenForNative(value: string): string {
  // Dot-notation: blue.500
  const dotMatch = value.match(/^([a-zA-Z]+)\.(\d+)$/);
  if (dotMatch) {
    const varName = `--kits-${dotMatch[1]}-${dotMatch[2]}`;
    return _activeColorMap[varName] ?? value;
  }

  // $-prefixed tokens: $spacing.4, $radii.lg, etc.
  if (value.startsWith('$')) {
    const dotIdx = value.indexOf('.');
    if (dotIdx > 1) {
      const category = value.substring(1, dotIdx);
      const key = value.substring(dotIdx + 1);
      switch (category) {
        case 'spacing': {
          const varName = `--kits-space-${key}`;
          return _activeColorMap[varName] ?? value;
        }
        case 'radii': {
          const varName = `--kits-radii-${key}`;
          return _activeColorMap[varName] ?? value;
        }
        case 'shadows': {
          const varName = `--kits-shadow-${key}`;
          return _activeColorMap[varName] ?? value;
        }
        case 'fontSizes': {
          const varName = `--kits-fontSize-${key}`;
          return _activeColorMap[varName] ?? value;
        }
        case 'fonts': {
          const varName = `--kits-font-${key}`;
          return _activeColorMap[varName] ?? value;
        }
      }
    }
  }

  // Semantic tokens: 'primary', 'danger', etc.
  const semanticVarName = `--kits-${value}`;
  if (_activeColorMap[semanticVarName]) {
    return _activeColorMap[semanticVarName]!;
  }

  return value;
}
export function createStyleContext(): StyleContext {
  const { width, height } = Dimensions.get('window');

  const orientation = width > height ? 'landscape' : 'portrait';
  const device = Math.min(width, height) >= 768 ? 'tablet' : 'phone';

  return {
    platform: Platform.OS as 'ios' | 'android',
    width,
    height,
    orientation,
    device,
    breakpoint: getCurrentBreakpoint(width),
  };
}
export const getCurrentBreakpoint = (
  width: number
): keyof typeof breakpoints => {
  const entries = Object.entries(breakpoints)
    .sort((a, b) => b[1] - a[1]);

  for (const [key, value] of entries) {
    if (width >= value) return key as keyof typeof breakpoints;
  }
  return 'base';
};

const breakpointOrder: (keyof typeof breakpoints)[] = [
  'base',
  'xs',
  'sm',
  'md',
  'lg',
  'xl',
  'xxl',
  'xxxl',
];

// ---------------------------------------------------------------------------
// CSS unit → React Native value conversion
// RN only accepts numbers (dp) or percentage strings for most layout props.
// 1rem = 16dp baseline, 1em = 16dp baseline, px is stripped to a number.
// Percentages (e.g. "50%") are passed through — RN supports them for dimensions.
// CSS variables var(--*) are resolved via CSS_VAR_MAP to their native values.
// ---------------------------------------------------------------------------
export function toNativeValue(value: any): any {
  if (typeof value !== 'string') return value;
  if (value === '0') return 0;

  // Theme token resolution: 'blue.500', 'primary', '$spacing.4' etc.
  if (isThemeToken(value)) {
    const resolved = resolveThemeTokenForNative(value);
    if (resolved !== value) return toNativeValue(resolved);
  }

  // CSS variable resolution: var(--xyz) → resolved hex color or value
  if (value.startsWith('var(')) {
    const resolved = resolveCssVar(value);
    // If resolution returned something different, recurse (it might be a rem value etc.)
    return resolved !== value ? toNativeValue(resolved) : value;
  }

  // rem → number  (1rem = 16dp)
  const remMatch = value.match(/^(-?\d*\.?\d+)rem$/);
  if (remMatch) return parseFloat(remMatch[1]!) * 16;

  // em → number  (1em = 16dp baseline)
  const emMatch = value.match(/^(-?\d*\.?\d+)em$/);
  if (emMatch) return parseFloat(emMatch[1]!) * 16;

  // px → number
  const pxMatch = value.match(/^(-?\d*\.?\d+)px$/);
  if (pxMatch) return parseFloat(pxMatch[1]!);

  // pc (pica) → number  (1pc = 12pt = 16dp)
  const pcMatch = value.match(/^(-?\d*\.?\d+)pc$/);
  if (pcMatch) return parseFloat(pcMatch[1]!) * 16;

  // pure number string → number
  const numMatch = value.match(/^(-?\d*\.?\d+)$/);
  if (numMatch) return parseFloat(numMatch[1]!);

  // Percentage strings, keywords, colors — pass through
  return value;
}

type ParsedBorder = {
  borderWidth?: number;
  borderStyle?: 'solid' | 'dotted' | 'dashed';
  borderColor?: string;
};

const BORDER_STYLES = ["solid", "dashed", "dotted", "double", "groove", "ridge", "inset", "outset"];

// Extract numeric border width, with rem/em/px unit conversion
function extractBorderWidth(part: string): number | undefined {
  // rem
  const remMatch = part.match(/^(\d+(\.\d+)?)rem$/);
  if (remMatch) return parseFloat(remMatch[1]!) * 16;
  // em
  const emMatch = part.match(/^(\d+(\.\d+)?)em$/);
  if (emMatch) return parseFloat(emMatch[1]!) * 16;
  // px or bare number
  const match = part.match(/^(\d+(\.\d+)?)(px)?$/);
  if (!match) return undefined;
  const n = Number(match[1]);
  return Number.isFinite(n) ? n : undefined;
}

const parseBorder = (value: string): ParsedBorder => {
  if (!value || typeof value !== "string") return {};

  const parts = value.trim().split(/\s+/);

  let borderWidth: number | undefined;
  let borderStyle: "solid" | "dotted" | "dashed" | undefined;
  let borderColor: string | undefined;

  for (const part of parts) {
    // Detect width (e.g., "1px", "2rem", "0.5em", "0", "5", etc.)
    if (!borderWidth && /^(\d+(\.\d+)?(px|em|rem|%)?)$/.test(part)) {
      const extracted = extractBorderWidth(part);
      if (extracted !== undefined) {
        borderWidth = extracted;
        continue;
      }
      continue;
    }

    // Detect style
    if (!borderStyle && BORDER_STYLES.includes(part)) {
      borderStyle = part as "solid" | "dotted" | "dashed";
      continue;
    }

    // Detect color (hex, rgb, rgba, hsl, named colors — not CSS vars)
    if (
      !borderColor &&
      (/^#([0-9a-f]{3}|[0-9a-f]{6}|[0-9a-f]{8})$/i.test(part) ||
        /^rgb(a)?\(/.test(part) ||
        /^hsl(a)?\(/.test(part) ||
        /^[a-zA-Z]+$/.test(part))
    ) {
      borderColor = part;
    }
  }

  return { borderWidth, borderStyle, borderColor };
};

const isPrimitive = (v: any) =>
  typeof v === 'number' || typeof v === 'string';

export function resolveResponsiveValue<T>(
  input: any,
  ctx: StyleContext
): T | undefined {

  // 1. Direct value
  if (input == null || isPrimitive(input)) {
    return input as T;
  }

  // 2. Array syntax — cascade like CSS: find the last defined value at or
  //    before the current breakpoint index, matching web's min-width cascade.
  if (Array.isArray(input)) {
    const index = breakpointOrder.indexOf(ctx.breakpoint);
    for (let i = index; i >= 0; i--) {
      const val = input[i];
      if (val !== null && val !== undefined) return val as T;
    }
    return undefined;
  }

  // 3. Platform
  if (ctx.platform in input) {
    return resolveResponsiveValue(input[ctx.platform], ctx);
  }

  // 4. Device
  if (ctx.device in input) {
    return resolveResponsiveValue(input[ctx.device], ctx);
  }

  // 5. Orientation
  if (ctx.orientation in input) {
    return resolveResponsiveValue(input[ctx.orientation], ctx);
  }

  // 6. Breakpoints (fallback chain)
  for (
    let i = breakpointOrder.indexOf(ctx.breakpoint);
    i >= 0;
    i--
  ) {
    const bp = breakpointOrder[i];
    if (bp && bp in input) return input[bp];
  }

  return undefined;
}

const resolveSizing = (value: any, key: string, ctx: StyleContext) => {
  if (value === 'full') return '100%';
  if (value === 'screen') {
    const isH = key === 'h' || key === 'height' || key === 'minH' || key === 'maxH';
    return isH ? ctx.height : ctx.width;
  }
  return toNativeValue(value);
};

const parseBorderSide = (resolved: string, side: string): Record<string, any> => {
  const parsed = parseBorder(resolved);
  const styles: Record<string, any> = {};
  if (parsed.borderWidth !== undefined) styles[`${side}Width`] = parsed.borderWidth;
  if (parsed.borderColor) styles[`${side}Color`] = parsed.borderColor;
  if (parsed.borderStyle) styles[`${side}Style`] = parsed.borderStyle;
  return styles;
};

export const style = (props: IStyleClasses, externalCtx?: StyleContext) => {
  const ctx = externalCtx ?? createStyleContext();
  const finalStyles: Partial<ViewStyle> = {};
  const transforms: { [key: string]: any }[] = [];
  const apply = (key: string, value: any) => {
    const mapped = mapCssProperties[key];
    if (!mapped) return;
    const converted = toNativeValue(value);
    (finalStyles as Record<string, any>)[mapped] = converted;
  };

  Object.entries(props).forEach(([key, val]) => {
    if (val === undefined || key.startsWith('_')) return;

    const resolved = resolveResponsiveValue<any>(val, ctx);
    if (resolved === undefined) return;

    switch (key) {
      // Margin shorthands
      case 'mx':
        finalStyles.marginLeft = toNativeValue(resolved);
        finalStyles.marginRight = toNativeValue(resolved);
        break;
      case 'my':
        finalStyles.marginTop = toNativeValue(resolved);
        finalStyles.marginBottom = toNativeValue(resolved);
        break;

      // Padding shorthands
      case 'px':
        finalStyles.paddingLeft = toNativeValue(resolved);
        finalStyles.paddingRight = toNativeValue(resolved);
        break;
      case 'py':
        finalStyles.paddingTop = toNativeValue(resolved);
        finalStyles.paddingBottom = toNativeValue(resolved);
        break;

      // Sizing with "full"/"screen" support
      case 'w':
      case 'width':
        finalStyles.width = resolveSizing(resolved, key, ctx);
        break;
      case 'h':
      case 'height':
        finalStyles.height = resolveSizing(resolved, key, ctx);
        break;
      case 'minW':
      case 'minWidth':
        finalStyles.minWidth = resolveSizing(resolved, key, ctx);
        break;
      case 'maxW':
      case 'maxWidth':
        finalStyles.maxWidth = resolveSizing(resolved, key, ctx);
        break;
      case 'minH':
      case 'minHeight':
        finalStyles.minHeight = resolveSizing(resolved, key, ctx);
        break;
      case 'maxH':
      case 'maxHeight':
        finalStyles.maxHeight = resolveSizing(resolved, key, ctx);
        break;

      // Opacity normalization (0-100 -> 0-1)
      case 'opacity':
        finalStyles.opacity = typeof resolved === 'number' ? resolved / 100 : resolved;
        break;

      // Border shorthand
      case 'border':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorder(resolved));
        }
        break;
      // Border side-specific
      case 'borderTop':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderTop'));
        }
        break;
      case 'borderBottom':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderBottom'));
        }
        break;
      case 'borderLeft':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderLeft'));
        }
        break;
      case 'borderRight':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderRight'));
        }
        break;
      // Border X/Y shorthands
      case 'borderX':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderLeft'));
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderRight'));
        }
        break;
      case 'borderY':
        if (typeof resolved === 'string') {
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderTop'));
          Object.assign(finalStyles, parseBorderSide(resolved, 'borderBottom'));
        }
        break;

      // Border radius shorthands
      case 'borderRadiusTop':
        finalStyles.borderTopLeftRadius = toNativeValue(resolved);
        finalStyles.borderTopRightRadius = toNativeValue(resolved);
        break;
      case 'borderRadiusBottom':
        finalStyles.borderBottomLeftRadius = toNativeValue(resolved);
        finalStyles.borderBottomRightRadius = toNativeValue(resolved);
        break;
      case 'borderRadiusLeft':
        finalStyles.borderTopLeftRadius = toNativeValue(resolved);
        finalStyles.borderBottomLeftRadius = toNativeValue(resolved);
        break;
      case 'borderRadiusRight':
        finalStyles.borderTopRightRadius = toNativeValue(resolved);
        finalStyles.borderBottomRightRadius = toNativeValue(resolved);
        break;

      // Transform props -> RN transform array
      case 'translateX':
        transforms.push({ translateX: typeof resolved === 'string' ? parseFloat(resolved) || 0 : resolved });
        break;
      case 'translateY':
        transforms.push({ translateY: typeof resolved === 'string' ? parseFloat(resolved) || 0 : resolved });
        break;
      case 'rotate':
        transforms.push({ rotate: typeof resolved === 'number' ? `${resolved}deg` : resolved });
        break;

      default:
        apply(key, resolved);
        break;
    }
  });

  if (transforms.length > 0) {
    finalStyles.transform = transforms as any;
  }

  return finalStyles;
};
